import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c,e as o}from"./app-be253e4c.js";const s={},n=o(`<h1 id="rcp命令" tabindex="-1"><a class="header-anchor" href="#rcp命令" aria-hidden="true">#</a> rcp命令</h1><p><code>rcp</code>命令用于复制远程文件或目录，如同时指定两个以上的文件或目录，且最后的目标位置是一个已经存在的目录，则它会把前面指定的所有文件或目录复制到该目录中，执行<code>rcp</code>命令以后不会有返回信息，仅需要在目标目录下查看文件或目录是否复制成功即可，<code>rcp</code>不提示输入密码，其通过<code>rsh</code>执行远程执行 ，并且需要相同的授权。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rcp</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>origin<span class="token punctuation">]</span> <span class="token punctuation">[</span>target<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-r</code>: 递归地把源目录中的所有内容拷贝到目标目录中，要使用这个选项，目标位置必须是一个目录。</li><li><code>-p</code>: 保留源文件的修改时间和模式，包括拥有者、所属群组、权限与时间，忽略<code>umask</code>。</li><li><code>-k</code>: 请求<code>rcp</code>获得在指定区域内的远程主机的<code>Kerberos</code>许可，而不是获得由<code>krb_relmofhost</code>确定的远程主机区域内的远程主机的<code>Kerberos</code>许可。</li><li><code>-x</code>: 为传送的所有数据打开<code>DES</code>加密，这会影响响应时间和<code>CPU</code>使用率，但是可以提高安全性。</li><li><code>-D</code>: 指定远程服务器的端口号。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>远程复制<code>file.txt</code>文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rcp</span> root@1.1.1.1:/file.txt file.txt
</code></pre></div>`,9),d=[n];function t(r,i){return a(),c("div",null,d)}const h=e(s,[["render",t],["__file","rcp.html.vue"]]);export{h as default};
